/*
Calculates lit/len and dist pairs for given data.
If instart is larger than 0, it uses values before instart as starting
dictionary.
*/
void ZopfliLZ77Optimal(ZopfliBlockState *s,
                       const unsigned char *in, size_t instart, size_t inend,
                       int numiterations,
                       ZopfliLZ77Store *store)
/* Squeeze driver, sibling of ZopfliLZ77OptimalFixed.  The block state and the
   output store are live, distinct objects; the parse walks [instart, inend) so
   instart never exceeds inend.  The block-length bound keeps the two
   `malloc(... * (blocksize + 1))` sizings (for length_array and costs) inside
   CBMC's max object size, mirroring the Fixed sibling's bound.  Unlike the Fixed
   variant this function never assigns s->blockstart / s->blockend itself, so no
   exact-value postcondition on them is available; the frame allows the whole
   state and store objects to change, since the output is produced deep inside
   the inlined LZ77OptimalRun / ZopfliCopyLZ77Store calls. */

